def minHeapify(arr, n):
    for i in range(n):
        if arr[i] > arr[0]:
            temp = arr[i]
            arr[i] = arr[0]
            arr[0] = temp

    n = len(arr)  # CORRECT UPDATE OF min-heap SIZE
    return arr, n

if __name__ == '__main__':
    n = int(input().split()[0])
    arr = list(map(int, input().split()))
    arr, n = minHeapify(arr, n)
    print(n)
